/bin/zsh -lc "python - <<'PY'
import csv, ast, json
T1={'北京','上海','广州','深圳'}
T2={'杭州','成都','武汉','南京','西安'}
limits={
'T1': {'meals':200,'hotel':500,'transport':200},
'T2': {'meals':150,'hotel':350,'transport':150},
'T3': {'meals':100,'hotel':250,'transport':100},
}
def tier(city): return 'T1' if city in T1 else 'T2' if city in T2 else 'T3'
def level(amount):
    if amount==0: return 'N/A'
    if amount<=5000: return 'auto'
    if amount<=20000: return 'manager'
    return 'director'
out=[]
with open('input.csv', newline='', encoding='utf-8') as f:
    for row in csv.DictReader(f):
        days=int(row['days'])
        client=row['client_facing']=='True'
        items=ast.literal_eval(row['items'])
        if days>14:
            out.append({'id':row['id'],'result':'REJECT','approved_amount':0,'approval_level':'N/A'})
            continue
        citytier=tier(row['city'])
        approved=0
        rejected=0
        for it in items:
            cat=it['category']; amt=it['amount']; has=it['has_receipt']
            if amt>200 and not has:
                rejected+=1; continue
            if cat=='entertainment':
                if not client:
                    rejected+=1; continue
                approved += amt
            else:
                approved += min(amt, limits[citytier][cat]*days)
        if approved==0:
            result='REJECT'
        elif rejected:
            result='PARTIAL'
        else:
            result='APPROVE'
        out.append({'id':row['id'],'result':result,'approved_amount':approved,'approval_level':level(approved)})
print(json.dumps(out, ensure_ascii=False, indent=2))
PY"

